const fs = require('fs');
const token = fs.readFileSync('/var/run/secrets/kubernetes.io/serviceaccount/token', 'utf8').trim();
return [{ json: { ...($input.first().json), saToken: token } }];

const http = require('http');
const pods = $input.first().json;
const namespace = $('Set Parameters').first().json.namespace;
const email = $('Set Parameters').first().json.destinationEmail;
const podList = pods.items || [];
const ts = new Date().toISOString();

let rows = '';
let allHealthy = true;

for (const pod of podList) {
  const name = pod.metadata.name;
  const phase = pod.status.phase;
  const ready = pod.status.containerStatuses?.[0]?.ready ? 'Yes' : 'No';
  const restarts = pod.status.containerStatuses?.[0]?.restartCount || 0;
  const image = pod.spec.containers?.[0]?.image || 'unknown';
  const version = image.split(':')[1] || 'latest';
  const statusColor = phase === 'Running' ? '#92D400' : '#F0AB00';
  if (phase !== 'Running') allHealthy = false;
  rows += '<tr><td style="padding:10px;border-bottom:1px solid #E0E0E0;">' + name + '</td><td style="padding:10px;text-align:center;border-bottom:1px solid #E0E0E0;"><span style="background:' + statusColor + ';padding:2px 10px;border-radius:12px;font-size:11px;font-weight:600;">' + phase + '</span></td><td style="padding:10px;text-align:center;border-bottom:1px solid #E0E0E0;">' + ready + '</td><td style="padding:10px;text-align:center;border-bottom:1px solid #E0E0E0;">' + restarts + '</td><td style="padding:10px;text-align:center;border-bottom:1px solid #E0E0E0;">' + version + '</td></tr>';
}

const healthStatus = allHealthy && podList.length > 0 ? 'HEALTHY' : 'DEGRADED';
const healthColor = healthStatus === 'HEALTHY' ? '#92D400' : '#F0AB00';
const healthBg = healthStatus === 'HEALTHY' ? '#F0FFF0' : '#FFFBF0';
const subject = '[Red Hat OpenShift] Redis Health Report | ' + namespace + ' | ' + ts;

const html = '<html><body style="margin:0;padding:0;background:#f0f0f0;font-family:Red Hat Display,Arial,sans-serif;"><table width="100%" cellpadding="0" cellspacing="0" style="background:#f0f0f0;"><tr><td align="center" style="padding:24px;"><table width="640" style="max-width:640px;width:100%;"><tr><td style="background:#151515;padding:16px 32px;border-radius:8px 8px 0 0;"><span style="color:#EE0000;font-size:20px;font-weight:700;">Red Hat</span><span style="float:right;color:#C6C6C6;font-size:12px;line-height:28px;">OpenShift Developer Sandbox</span></td></tr><tr><td style="background:#DC382D;padding:28px 32px;"><h1 style="margin:0;font-size:24px;color:#FFF;">Redis Health Report</h1><p style="margin:6px 0 0;font-size:14px;color:rgba(255,255,255,.85);">Automated Redis deployment monitoring on OpenShift</p></td></tr><tr><td style="background:#292929;padding:0;"><table width="100%"><tr><td style="padding:12px 16px;text-align:center;color:#A3A3A3;font-size:11px;border-right:1px solid #3C3C3C;width:33%;"><b style="display:block;color:#FFF;font-size:13px;">' + namespace + '</b>Namespace</td><td style="padding:12px 16px;text-align:center;color:#A3A3A3;font-size:11px;border-right:1px solid #3C3C3C;width:34%;"><b style="display:block;color:#FFF;font-size:13px;">' + ts + '</b>Generated</td><td style="padding:12px 16px;text-align:center;color:#A3A3A3;font-size:11px;width:33%;"><b style="display:block;color:#FFF;font-size:13px;">' + podList.length + ' Pod(s)</b>Redis</td></tr></table></td></tr><tr><td style="background:#FFF;padding:28px 32px;"><h2 style="margin:0 0 16px;font-size:17px;border-bottom:2px solid #DC382D;padding-bottom:10px;">Redis Deployment Status</h2><table style="width:100%;border-collapse:collapse;font-size:13px;"><tr style="background:#F5F5F5;"><th style="padding:10px;text-align:left;border-bottom:2px solid #DC382D;">Pod</th><th style="padding:10px;text-align:center;border-bottom:2px solid #DC382D;">Status</th><th style="padding:10px;text-align:center;border-bottom:2px solid #DC382D;">Ready</th><th style="padding:10px;text-align:center;border-bottom:2px solid #DC382D;">Restarts</th><th style="padding:10px;text-align:center;border-bottom:2px solid #DC382D;">Version</th></tr>' + rows + '</table><div style="margin-top:20px;padding:14px;background:' + healthBg + ';border-left:4px solid ' + healthColor + ';border-radius:4px;"><strong>Overall Status: ' + healthStatus + '</strong><p style="margin:6px 0 0;font-size:13px;color:#333;">' + podList.length + ' Redis pod(s) monitored in namespace ' + namespace + '.</p></div></td></tr><tr><td style="background:#F5F5F5;padding:16px 32px;border-top:1px solid #E0E0E0;text-align:center;"><span style="display:inline-block;background:#EE0000;color:white;font-size:10px;font-weight:700;padding:4px 10px;border-radius:3px;">RED HAT</span> <span style="font-size:11px;color:#6A6E73;margin:0 8px;">OpenShift</span> <span style="font-size:11px;color:#DC382D;font-weight:600;margin:0 8px;">Redis</span> <span style="font-size:11px;color:#6A6E73;margin:0 8px;">n8n</span></td></tr><tr><td style="background:#151515;padding:20px 32px;border-radius:0 0 8px 8px;text-align:center;"><p style="margin:0;font-size:12px;color:#A3A3A3;">Auto-generated by n8n on <b style="color:#FFF;">Red Hat OpenShift Developer Sandbox</b></p></td></tr></table></td></tr></table></body></html>';

const mailBody = JSON.stringify({
  From: { Name: 'n8n Redis Monitor', Email: 'redis-monitor@n8n.local' },
  To: [{ Name: 'Admin', Email: email }],
  Subject: subject,
  HTML: html
});

return new Promise((resolve, reject) => {
  const req = http.request({
    hostname: 'n8n-mailpit',
    port: 8025,
    path: '/api/v1/send',
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(mailBody)
    }
  }, (res) => {
    let data = '';
    res.on('data', (chunk) => { data += chunk; });
    res.on('end', () => {
      resolve([{
        json: {
          mailpitStatus: res.statusCode,
          mailpitResponse: data,
          subject,
          healthStatus,
          podCount: podList.length,
          namespace,
          timestamp: ts
        }
      }]);
    });
  });
  req.on('error', (e) => reject(new Error('Mailpit send failed: ' + e.message)));
  req.write(mailBody);
  req.end();
});
